import{_ as e,o as t,c as a,ag as n}from"./chunks/framework.CvgP6Fyv.js";const k=JSON.parse('{"title":"Click Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"features/click-tracking.md","filePath":"features/click-tracking.md"}'),r={name:"features/click-tracking.md"};function o(l,i,s,c,d,h){return t(),a("div",null,[...i[0]||(i[0]=[n('<h1 id="click-tracking" tabindex="-1">Click Tracking <a class="header-anchor" href="#click-tracking" aria-label="Permalink to &quot;Click Tracking&quot;">​</a></h1><p>Click tracking monitors which links recipients click in your emails. When enabled, SendGrail rewrites links in HTML emails to pass through a tracking endpoint that records the click before redirecting to the original destination.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><ol><li><p><strong>Link rewriting</strong> -- All <code>&lt;a href&gt;</code> links in HTML emails are rewritten to point to a tracking URL on your WordPress site.</p></li><li><p><strong>Tracking URL format</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/wp-json/sendgrail/v2/t/click/{tracking_id}/{link_hash}</span></span></code></pre></div><ul><li><code>tracking_id</code> -- The unique UUID assigned to the email</li><li><code>link_hash</code> -- The first 12 characters of the MD5 hash of the original URL</li></ul></li><li><p><strong>URL map storage</strong> -- A mapping of link hashes to original URLs is stored in a WordPress transient with a <strong>30-day TTL</strong>.</p></li><li><p><strong>Click handling</strong> -- When a recipient clicks a tracked link:</p><ul><li>The click event is recorded (IP, User-Agent, original URL, timestamp)</li><li>A <strong>302 redirect</strong> sends the user to the original destination URL</li></ul></li><li><p><strong>Denormalized counts</strong> -- For fast access, <code>click_count</code> and <code>first_clicked_at</code> are stored directly on the email log entry.</p></li></ol><h2 id="skipped-links" tabindex="-1">Skipped Links <a class="header-anchor" href="#skipped-links" aria-label="Permalink to &quot;Skipped Links&quot;">​</a></h2><p>The following link types are <strong>not rewritten</strong> and are left as-is:</p><table tabindex="0"><thead><tr><th>Link Type</th><th>Example</th></tr></thead><tbody><tr><td>Mailto links</td><td><code>mailto:user@example.com</code></td></tr><tr><td>Telephone links</td><td><code>tel:+1234567890</code></td></tr><tr><td>Anchor links</td><td><code>#section-name</code></td></tr><tr><td>JavaScript links</td><td><code>javascript:void(0)</code></td></tr><tr><td>Already-tracked URLs</td><td>Links that already point to the SendGrail tracking endpoint</td></tr></tbody></table><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Click tracking is controlled by the <code>enable_click_tracking</code> setting in the plugin settings page. Toggle it on or off as needed.</p><p>When disabled, links in outgoing emails are not modified and no click events are recorded.</p><h2 id="viewing-click-data" tabindex="-1">Viewing Click Data <a class="header-anchor" href="#viewing-click-data" aria-label="Permalink to &quot;Viewing Click Data&quot;">​</a></h2><p>Click tracking data is available in the <a href="/features/email-logging#email-report-view">email report view</a> for each individual email:</p><ul><li><strong>Click count</strong> -- Total number of link clicks across all links in the email</li><li><strong>First clicked</strong> -- Timestamp of the first recorded click</li><li><strong>Event timeline</strong> -- Chronological list of click events showing which URL was clicked, along with IP, User-Agent, and timestamp</li></ul><h2 id="url-map-expiration" tabindex="-1">URL Map Expiration <a class="header-anchor" href="#url-map-expiration" aria-label="Permalink to &quot;URL Map Expiration&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The URL map transient has a <strong>30-day TTL</strong>. After 30 days, tracked links in older emails will no longer redirect correctly because the original URL can no longer be resolved from the link hash. Recipients clicking expired tracked links will see an error.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If long-term link functionality is critical, consider the retention implications of the 30-day transient window when planning your email retention policy.</p></div><h2 id="privacy-considerations" tabindex="-1">Privacy Considerations <a class="header-anchor" href="#privacy-considerations" aria-label="Permalink to &quot;Privacy Considerations&quot;">​</a></h2><p>Click tracking records IP addresses, User-Agent strings, and the URLs that recipients interact with. This data can reveal user behavior patterns. Ensure your use of click tracking complies with applicable privacy regulations and that your privacy policy appropriately discloses this practice.</p>',18)])])}const g=e(r,[["render",o]]);export{k as __pageData,g as default};
